#include <bits/stdc++.h>
using namespace std;
const int N=500005;
struct Node{
	int ans,qz,hz,sum;
}t[4*N];
int n,m,p[N];
void Build(int cur,int l,int r){
	if(l==r){
		t[cur]={p[l],p[l],p[l],p[l]};
		return;
	}
	int mid=(l+r)/2;
	Build(cur*2,l,mid);
	Build(cur*2+1,mid+1,r);
	t[cur].sum=t[cur*2].sum+t[cur*2+1].sum;
	t[cur].qz=max(t[cur*2].sum+t[cur*2+1].qz,t[cur*2].qz);
	t[cur].hz=max(t[cur*2+1].sum+t[cur*2].hz,t[cur*2+1].hz);
	t[cur].ans=max(max(t[cur*2].ans,t[cur*2+1].ans),t[cur*2].hz+t[cur*2+1].qz);
}
void Modify(int cur,int l,int r,int a,int b){
	if(l==r && l==a){
		p[l]=b;
		t[cur]={p[l],p[l],p[l],p[l]};
		return;
	}
	int mid=(l+r)/2;
	if(a>mid)
		Modify(cur*2+1,mid+1,r,a,b);
	else
		Modify(cur*2,l,mid,a,b);
	t[cur].sum=t[cur*2].sum+t[cur*2+1].sum;
	t[cur].qz=max(t[cur*2].sum+t[cur*2+1].qz,t[cur*2].qz);
	t[cur].hz=max(t[cur*2+1].sum+t[cur*2].hz,t[cur*2+1].hz);
	t[cur].ans=max(max(t[cur*2].ans,t[cur*2+1].ans),t[cur*2].hz+t[cur*2+1].qz);
}
Node Find(int cur,int l,int r,int a,int b){
	if(l>=a && r<=b)
		return t[cur];
	int mid=(l+r)/2;
	if(b<=mid)
		return Find(cur*2,l,mid,a,b);
	else if(a>mid)
		return Find(cur*2+1,mid+1,r,a,b);
	else{
		Node t,x=Find(cur*2,l,mid,a,b),y=Find(cur*2+1,mid+1,r,a,b);
		t.sum=x.sum+y.sum;
		t.qz=max(x.qz,x.sum+y.qz);
		t.hz=max(y.hz,y.sum+x.hz);
		t.ans=max(max(x.ans,y.ans),x.hz+y.qz);
		return t;
	}
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    	cin>>p[i];
    Build(1,1,n);
    while(m--){
    	int k,a,b;
    	cin>>k>>a>>b;
    	if(k==1){
    	    if(a>b)
    	        swap(a,b);
    	    cout<<Find(1,1,n,a,b).ans<<'\n';
    	}
    	if(k==2)
    		Modify(1,1,n,a,b);
	}
    return 0;
}
